  full_document = '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "seoul-suwon-hwaseong-waujeongsa-starfield", "locale": "en", "product_id": "seoul-suwon-hwaseong-waujeongsa-starfield", "seo": {"pageTitle": "Suwon Hwaseong, Waujeongsa & Starfield Day Tour | AtoC Korea", "metaDescription": "9–10-hour day trip from Seoul: UNESCO Suwon Hwaseong Fortress, Starfield Suwon Library, and Waujeongsa Temple with its giant outdoor Buddha. EN guide, transfers.", "ogImage": "https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "primaryKeywords": ["Suwon Hwaseong day tour", "Waujeongsa Temple Yongin", "Starfield Library Suwon", "Seoul Suwon heritage tour", "Hwaseong Fortress UNESCO tour"], "title": "Suwon Hwaseong, Waujeongsa Temple & Starfield Library Heritage Day Tour | AtoC Korea"}, "catalog_card": {"slug": "seoul-suwon-hwaseong-waujeongsa-starfield", "title": "Suwon: Hwaseong, Waujeongsa & Starfield", "subtitle": "UNESCO fortress, mountain temple, and viral library—Korea''s past, spirit, and present in one Seoul day-trip.", "region": "Suwon & Yongin", "duration": "9–10 hours", "stopsCount": 4, "rating": 0, "reviewCount": 0, "badges": ["UNESCO Heritage", "Heritage + Modern Day Trip", "Admission Included"], "heroImage": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "thumbnail": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "priceLabel": "From US$51 per person (was $54, 6% off)", "shortCardDescription": "A small-group day-trip from Seoul covering three contrasting sides of Korea: the UNESCO-listed Suwon Hwaseong Fortress (18th-century military architecture), the photogenic Starfield Suwon Library (contemporary cultural icon), and Waujeongsa Temple in Yongin (giant outdoor Buddha and stone bell). Strong heritage value with included transport and admission.", "tags": ["unesco_heritage", "heritage__modern_day_trip", "admission_included"]}, "headlineLine1": "Suwon Heritage Day", "headlineLine2": "Hwaseong, Waujeongsa & Starfield", "price": {"amountLabel": "51", "currency": "USD", "per": "person", "salePriceUsd": 51, "originalPriceUsd": 54, "discountPercent": 6}, "hero": {"imageUrl": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "imagePosition": "center 50%", "tagline": "From an 18th-century UNESCO fortress to one of Korea''s most photographed contemporary libraries to a peaceful mountain Buddhist temple—three sides of Korea in one balanced day.", "pills": ["UNESCO Site", "Admission Included", "Round-Trip Seoul Transfers"], "meta": {"duration": "9–10 hours", "region": "Suwon & Yongin", "stops": "4 stops", "rating": 0, "ratingStars": 0}}, "subnavItems": [{"id": "overview", "label": "Overview"}, {"id": "itinerary", "label": "Itinerary"}, {"id": "details", "label": "Details"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "Reviews"}], "glanceItems": [{"icon": "camera", "label": "Photo Value", "value": "Excellent", "level": 5}, {"icon": "mountain", "label": "Scenic", "value": "Good", "level": 4}, {"icon": "footprints", "label": "Walking", "value": "Moderate", "level": 3}, {"icon": "cloud-rain", "label": "Rain Safety", "value": "Good", "level": 4}, {"icon": "users", "label": "Family Fit", "value": "Good", "level": 4}, {"icon": "gauge", "label": "Balance", "value": "Balanced", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 1", "caption": "Suwon Hwaseong Fortress — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp", "location": "Waujeongsa Temple", "alt": "Waujeongsa Temple — gallery image 1", "caption": "Waujeongsa Temple — photo 1"}, {"id": 3, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 2", "caption": "Suwon Hwaseong Fortress — photo 2"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 3", "caption": "Suwon Hwaseong Fortress — photo 3"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 4", "caption": "Suwon Hwaseong Fortress — photo 4"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 5", "caption": "Suwon Hwaseong Fortress — photo 5"}, {"id": 7, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 6", "caption": "Suwon Hwaseong Fortress — photo 6"}, {"id": 8, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp", "location": "Waujeongsa Temple", "alt": "Waujeongsa Temple — gallery image 2", "caption": "Waujeongsa Temple — photo 2"}, {"id": 9, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp", "location": "Waujeongsa Temple", "alt": "Waujeongsa Temple — gallery image 3", "caption": "Waujeongsa Temple — photo 3"}, {"id": 10, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp", "location": "Waujeongsa Temple", "alt": "Waujeongsa Temple — gallery image 4", "caption": "Waujeongsa Temple — photo 4"}, {"id": 11, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp", "location": "Waujeongsa Temple", "alt": "Waujeongsa Temple — gallery image 5", "caption": "Waujeongsa Temple — photo 5"}], "itineraryStops": [{"number": 1, "time": "≈ 10:00", "duration": "75 min", "name": "Suwon Hwaseong Fortress", "category": "UNESCO Fortress", "description": "**Suwon Hwaseong (수원화성) — UNESCO World Heritage Site since 1997** — is Korea''s only walled fortress city preserved with its original 10-volume construction record (Hwaseong Seongyeok Uigwe, separately inscribed on the UNESCO Memory of the World Register in 2007). Built **1794-1796 in just 2 years 9 months** under King Jeongjo (정조, 22nd Joseon king, r. \n\n1776-1800), Hwaseong was the king''s project to relocate the Joseon capital from Hanyang (Seoul) to Suwon — and to honor his father Crown Prince Sado, who was sealed alive in a rice chest by his own father King Yeongjo in 1762. \n\nThe fortress was designed by **Jeong Yak-yong (정약용, also known as Dasan)** — Joseon''s leading scholar-engineer of the Silhak (practical learning) school — who integrated traditional Korean defensive architecture with Chinese siege defense theory and emerging Western fortification science. \n\nJeong Yak-yong invented the **geojunggi (거중기)** — a pulley-and-block crane based on Western mechanical principles — for lifting heavy stones during construction; the first documented use of Western-style modern engineering in Korean construction. \n\nThe complete fortress wall is **5.74 km in circumference** enclosing 130 hectares with 41 strategic structures: 4 main gates (Janganmun north — the **largest existing royal gate in Korea**, larger than Seoul''s Sungnyemun; Paldalmun south; Hwaseomun west; Changnyongmun east), 4 angle towers, 4 command posts, 5 sentry platforms, 5 gun batteries, plus archery platforms, sluice gates, and beacon towers. \n\nToday''s guided walk covers the **most photogenic 1.2 km section between Janganmun (north main gate) and Hwaseomun (west gate, National Treasure No. 403)** — the highest density of preserved military structures, ~25-30 minutes of walking. Add the **Seojangdae (West Command Post)** atop Paldalsan Mountain for the fortress''s highest viewpoint and the king''s strategic command position. \n\n**Hwahongmun (north sluice gate)** with its 7 arches over Suwoncheon Stream is the most photographed structure of the fortress — especially in spring (cherry blossoms) and autumn (foliage). Tour group walks the wall on foot; an optional **Hwaseong Trolley** sightseeing tram (4,000 KRW adult, ~30 min, Yeonmudae→Paldalmun route) is available if schedule permits.", "highlights": ["**UNESCO World Heritage Site since 1997** — Korea''s only walled fortress city with original construction records", "Built 1794-1796 in 2 years 9 months under King Jeongjo (22nd Joseon king)", "Designed by Jeong Yak-yong using Korean + Chinese + Western fortification science", "Hwaseong Seongyeok Uigwe construction record — UNESCO Memory of the World 2007", "5.74 km circumference, 41 strategic military structures", "Janganmun north gate — **largest existing royal gate in Korea**", "1.2 km guided walk Janganmun → Hwaseomun (highest photo-density section)", "Hwahongmun 7-arch sluice gate — most photographed structure", "FREE for hanbok-wearers + last Wed of month + seniors 65+"], "timeUsed": ["Coach drop-off near Janganmun (~5 min)", "Brief group orientation at Janganmun (~5 min)", "Walk Janganmun → Hwaseomun via Hwaseo Janggak (~25-30 min)", "Photo time + reassembly at vehicle (~10 min)", "Optional Hwaseong Yeolcha sightseeing trolley Yeonmudae↔Paldalmun (~30 min one-way; ₩4,000 adult)"], "whyOnRoute": "The route''s UNESCO anchor — Korea''s only remaining walled fortress city, built 1794-1796 under King Jeongjo. The Janganmun → Hwaseomun walk (~1.2 km) gives the highest density of preserved military structures + the iconic Hwahongmun 7-arch sluice gate in a 75-min stop. Picked over the full 5.74 km loop because the route covers the most photographed and historically rich section while preserving time for the day''s three other heritage stops. Hwaseong is also the **mandatory anchor of any Suwon day-trip** because it physically encloses the Haenggung palace — meaning the morning Suwon block delivers UNESCO World Heritage credentials and Joseon royal-residence interiority before the route continues to Starfield and the Waujeongsa temple finale. The 1.2 km Janganmun → Hwaseomun wall section via Hwaseo Janggak is the highest-density preserved-military-architecture stretch in Korea (4 main gates + 5 secret gates + 4 sluices + Geojunggi-built ramparts coexist within 25-30 minutes walking time).", "visitBasics": {"hours": "Wall path 24 hours (no gates); recommended 09:00-18:00 summer / 09:00-17:00 winter; evening hours May-Oct Wed-Sun 18:00-21:30", "closed": "Open year-round (Hwaseong Trolley closed Mondays)", "admission": "Adults 1,000 / Youth 700 / Children 500 KRW (FREE: children ≤6, seniors 65+, hanbok-wearers, last Wed of month). Hwaseong Trolley separate 4,000 KRW", "walking": "Moderate — wall has steep sections at Seojangdae; stairs at gates; some sections wheelchair-difficult"}, "convenience": {"restroom": "At Janganmun, Hwaseomun, Paldalmun, and Yeonmudae", "parking": "Coach drop-off at Janganmun lot; designated coach parking at Yeonmudae"}, "smartNotes": {"photo": "**Hwahongmun (north sluice gate)** with 7 arches over Suwoncheon Stream — the iconic shot, especially in spring (cherry blossoms) and autumn (foliage). **Janganmun (largest existing royal gate in Korea)** at golden hour. **Seojangdae (west command post)** sunset over Paldalsan Mountain.", "facilities": "Visitor Information Center at Janganmun + Paldalmun + Hwaseong Haenggung Square. English-Korean signage throughout. Hwaseong audio guide rental at Janganmun.", "tip": "Wear comfortable shoes — wall stones are uneven. Hanbok rental shops at Haenggung Square give FREE fortress + palace admission. **Avoid full 5.74 km loop unless allowing 2.5+ hours** — the Janganmun → Hwaseomun section gives the highest per-meter heritage density."}, "_poi_meta": {"poi_key": "hwaseong_fortress", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-04-29", "sources": ["UNESCO WHC", "VisitKorea", "KoreaToDo", "Suwon CVB", "UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)", "Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)", "Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)", "Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)", "Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]}, "image": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "images": ["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "/images/tours/suwon-hwaseong/photo-002.webp"], "imageCredits": [{"url": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/photo-002.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 1", "alt": "Suwon Hwaseong Fortress — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 2", "alt": "Suwon Hwaseong Fortress — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 3", "alt": "Suwon Hwaseong Fortress — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 4", "alt": "Suwon Hwaseong Fortress — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 5", "alt": "Suwon Hwaseong Fortress — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 6", "alt": "Suwon Hwaseong Fortress — gallery image 6"}]}, {"number": 2, "time": "≈ 11:30", "duration": "75 min", "name": "Hwaseong Haenggung Palace", "category": "Joseon Royal Detached Palace", "description": "**Hwaseong Haenggung (화성행궁) — Korea''s largest existing haenggung (detached palace)** — was built 1789-1796 under King Jeongjo as part of the unified Hwaseong fortress city plan. \n\nA **haenggung** is a temporary/detached royal residence used by Joseon kings during travel, war refuge, or special ceremonies; Hwaseong Haenggung surpasses Onyang, Bukhansan, and Namhansan haenggung in scale. King Jeongjo built it primarily to stay overnight when visiting his executed father Crown Prince Sado''s tomb (Hyeollyungwon, now called Yungneung Royal Tomb, 4 km south) — a pilgrimage he made **13 times during his reign**. \n\nThe most famous of these journeys was the **1795 royal procession** with 6,000 attendants and 1,400 horses, celebrating the 60th birthday of Lady Hyegyeong (the king''s mother and Sado''s widow). \n\nThe 1795 procession is documented in the **Wonhaeng Eulmyo Jeongni Uigwe — UNESCO Memory of the World register since 2007**. The palace originally comprised **576 kan (rooms/structural bays)** functioning as a complete miniature royal residence with throne hall (Bongsudang), secondary hall (Naknamheon), residence quarters (Janganheon), kitchens, military offices, and guards'' quarters. \n\n**Largely destroyed during Japanese colonial period** (1910-1945) when the Japanese converted the palace site into Suwon Provincial Hospital and Police Station. \n\n**Restoration began 1996** following the original Hwaseong Seongyeok Uigwe construction record; first phase complete 2003 (Bongsudang, Naknamheon, Janganheon, Yuyeotaek), second phase complete 2009 (Wuhwagwan royal kitchen, Sinpung-nu entrance gate). Restoration continues today. \n\n**Critical historical note: Naknamheon (낙남헌) is the ONLY building that survived from the original 1796 construction** — Japanese converted it into Police Station offices but did not demolish it. It is therefore the only AUTHENTIC original wood-and-tile structure on the site; all other buildings are reconstructions. \n\n**Daily Royal Guard Changing Ceremony** at Sinpungnu Gate — **Tuesday-Sunday 11:00 AM** (weather permitting), ~15 min, FREE. Recreates the Joseon-era palace gate ceremony with guards in red, blue, and yellow uniforms with traditional drums and horns. \n\nThe tour times arrival for the 11:00 ceremony when day-of-week permits. Filmed for K-drama **''Jewel in the Palace'' (Daejanggeum, 2003)** — the iconic Joseon-era hit (peak ratings around 57% in Korea) — making this one of Korea''s most-filmed sageuk locations.", "highlights": ["**Korea''s largest existing haenggung (detached palace)** — originally 576 rooms", "Built 1789-1796 alongside Hwaseong Fortress under King Jeongjo", "King Jeongjo made 13 royal pilgrimages here to honor his executed father Crown Prince Sado", "**Naknamheon = ONLY original 1796 structure remaining** (others are reconstructions)", "**Royal Guard Changing Ceremony Tue-Sun 11:00 AM at Sinpungnu Gate (FREE, ~15 min)**", "1795 Royal Procession documented in UNESCO Memory of the World", "Filming location for K-drama ''Jewel in the Palace'' (2003, peak ~57% rating on MBC)", "FREE for hanbok-wearers + seniors 65+ + children ≤6", "**Naknamheon (낙남헌) is the ONLY building surviving from the original 1796 construction** — Japanese colonial-era authorities converted it into Police Station offices but did not demolish it; every other Haenggung structure visible today is a post-1996 reconstruction following the Hwaseong Seongyeok Uigwe (UNESCO Memory of the World since 2007)"], "timeUsed": ["5 min walk from Hwaseong Fortress (Hwaseomun area)", "Arrive in time for **11:00 Royal Guard Changing Ceremony** at Sinpungnu (~15 min)", "Bongsudang Throne Hall + Naknamheon + Janganheon walk (~30 min)", "Photo time + reassembly at vehicle (~15 min)", "Optional Royal Guard Changing Ceremony at Sinpungnu Gate (Tue-Sun 11:00 AM, ~15 min, FREE — weather permitting)"], "whyOnRoute": "Pairs naturally with the fortress wall — the temporary royal residence is INSIDE the same UNESCO site, 5 minutes apart. Korea''s largest haenggung (576 rooms originally), with **Naknamheon the only authentic original structure** (the others are post-1996 reconstructions following the Hwaseong Uigwe). Time arrival for the Royal Guard Changing Ceremony (Tue-Sun 11:00 AM) which is FREE and ~15 min — one of the catalog''s strongest free cultural-experience hooks. Visiting Haenggung immediately after the fortress walls converts an abstract military-architecture lesson into lived royal-Joseon spatial experience — the same Bongsudang throne hall where King Jeongjo received officials in 1795 also hosted the lavish 60th-birthday banquet for his mother Lady Hyegyeong (depicted in the Banchado court-painting scrolls preserved in the Uigwe). A **Combined Fortress + Haenggung ticket** is sold at 3,500 KRW (vs 2,500 KRW separately) — a tangible value-added anchor for the Suwon stop. The Royal Guard Changing Ceremony at Sinpungnu Gate (Tue-Sun 11:00 AM, ~15 min, FREE) is timed to align with most Suwon-arrival schedules from a Seoul-departing day-trip.", "visitBasics": {"hours": "09:00-18:00 (last entry 17:30); summer May-Oct evening hours 18:00-21:00", "closed": "Open year-round", "admission": "Adult 1,500 / Teen 1,000 / Child 700 KRW. Combined Fortress + Haenggung 3,500 KRW. FREE for hanbok-wearers, seniors 65+, children ≤6", "walking": "Easy — palace grounds are mostly flat with some steps between courtyards"}, "convenience": {"restroom": "At main entrance, near Bongsudang, and at Haenggung Square", "parking": "Hwaseong Haenggung public parking; Haenggung Square paid lots"}, "smartNotes": {"photo": "**Bongsudang Main Hall** — the iconic throne hall shot. **Naknamheon** — the only original 1796 structure (the most historically authentic photo). **Royal Guard Changing Ceremony at Sinpungnu Gate** (Tue-Sun 11:00 AM). Hanbok-wearers in front of Sinpungnu — Suwon''s most popular hanbok photo spot.", "facilities": "Visitor Information Center, restrooms, gift shop. Haenggung Square cafes and hanbok rental (15,000-20,000 KRW for 4 hr). Suwon Tongdak (whole roast chicken) restaurants 5 min walk.", "tip": "**Time arrival for 11:00 AM Royal Guard Changing Ceremony Tue-Sun (FREE)**. Hanbok rental gives FREE admission to BOTH Fortress and Haenggung. **Naknamheon is THE single most historically important spot** — the only structure not rebuilt, surviving Japanese colonial demolition. Skip Mondays — Royal Guard Changing Ceremony performed Tue-Sun only."}, "_poi_meta": {"poi_key": "hwaseong_haenggung", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-04-29", "sources": ["VisitKorea", "Wikipedia", "Suwon CVB", "Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)", "Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)", "Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)", "Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)", "Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]}, "image": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "images": ["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "/images/tours/suwon-hwaseong/photo-002.webp"], "imageCredits": [{"url": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/photo-002.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 1", "alt": "Hwaseong Haenggung Palace — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 2", "alt": "Hwaseong Haenggung Palace — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 3", "alt": "Hwaseong Haenggung Palace — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 4", "alt": "Hwaseong Haenggung Palace — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 5", "alt": "Hwaseong Haenggung Palace — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 6", "alt": "Hwaseong Haenggung Palace — gallery image 6"}]}, {"number": 3, "time": "≈ 13:30", "duration": "90 min", "name": "Starfield Suwon Library & Mall", "category": "Modern Cultural Landmark + Lunch", "description": "**Starfield Library Suwon (별마당 도서관 수원)** — inside **Starfield Suwon, Shinsegae''s flagship ''second-generation'' Starfield mall opened January 26, 2024** as the fifth Starfield mall by Shinsegae Property; total investment exceeded 1 trillion KRW (~USD 750 million); ~334,000 m² gross floor area making it Korea''s 2nd-largest indoor mall after Starfield Hanam. \n\nDesigned in collaboration with **BCHO Partners (Cho Byoung-soo)** — the Korean firm responsible for the original COEX Starfield Library (2017) — Suwon''s library represents the second-generation iteration with **bookshelves rising up to 22 meters tall**, among the tallest cylindrical bookshelf structures in any Korean public space. \n\nThe library spans **4 floors (4F-7F atrium space)** housing **a large on-site collection of books and magazines** including Korean and international publications, periodicals, art books, and a dedicated children''s literature section on 4F. \n\n**FREE and open to the public** — no library card, no admission fee, accessible during all mall hours. Distinctive features: **Vinyl Record Listening Lounge** with curated Korean indie + jazz/classic rock vinyl; **monthly rotating art exhibition** in the atrium space; and **seasonal cherry blossom installation in the central atrium (March-April)** with thousands of pink LED petals — one of Suwon''s most photographed spring spots. \n\n**Lunch is included in this 90-min stop** at the **Eatopia food hall (B1F)** with 30+ restaurants ranging from quick-service Korean (5,000-10,000 KRW) to mid-tier Korean and international (15,000-25,000 KRW). Korean BBQ, bibimbap, kalguknsu, mandu, Japanese tonkatsu, Korean-Mexican fusion (Ko-Mex), Mountain Bus Australian burgers, pho, dumplings — full range of cuisines. \n\nAdjacent mall amenities: **Aquafield Suwon water park + Korean spa (B1-2F)** separate paid admission ~25,000-35,000 KRW; **Toy Kingdom (4F, Korea''s largest toy store)**; **CGV/MEGABOX dual cinema setup**. \n\n**Free Starfield shuttle bus** runs from Suwon Station Exit 4 every 10-15 min (~10 min ride) — easiest access from public transit. Annual visitors: **~28 million in first year (2024)** — among Korea''s top-3 most visited shopping destinations.", "highlights": ["**Shinsegae''s flagship 2nd-generation Starfield mall — opened January 26, 2024**", "Designed by BCHO Partners (also designed original COEX Starfield Library 2017)", "**4-floor library with 22-meter bookshelves** — among Korea''s tallest cylindrical bookshelves", "Large open reading collection accessible FREE", "Vinyl Record Listening Lounge", "Cherry blossom LED-petal installation (March-April)", "**Lunch included in stop** — Eatopia food hall B1F with 30+ restaurants", "Aquafield water park + Korean spa, Toy Kingdom (Korea''s largest), CGV+MEGABOX cinema", "Free Starfield shuttle from Suwon Station Exit 4 (~10 min)", "~28 million visitors in first year (2024)"], "timeUsed": ["30-min coach drive from Hwaseong Fortress to Starfield Suwon", "Lunch at Eatopia food hall (~30-45 min)", "Library + atrium walking + photo time (~30-40 min)", "Brief shopping browse + reassembly at coach (~10-15 min)", "Optional Eatopia food hall lunch (B1F, 30+ Korean + international restaurants; ~₩10,000-25,000 pp; 45-60 min)"], "whyOnRoute": "The ''modern Korea'' counterweight after the morning''s UNESCO heritage anchor. **Combined library + lunch stop** is the Tour 3 design — leveraging Eatopia food hall for lunch (eliminating a separate restaurant stop). The library + 22-meter bookshelves is the architectural showcase, and the all-indoor environment buffers any midday weather risk. **Lunch is built into the Starfield stop at the Eatopia food hall** — the 90-min combined stop fits naturally into the compact 4-stop day. For this midday pivot stop, Starfield Library functions as the **architectural-and-leisure breather** between Hwaseong''s heavy historical-architectural content and Waujeongsa''s intricate religious-syncretic content — the 22m atrium bookshelves deliver photo-stop satisfaction with **FREE admission**, while the surrounding mall (600+ retail brands, Eatopia food hall, Aquafield water park) enables flexible lunch + restroom + cafe + retail-pause logistics that neither Hwaseong nor Waujeongsa support directly.", "visitBasics": {"hours": "Mall 10:00-22:00; library accessible during all mall hours", "closed": "1-2 monthly closure days (typically Mondays — verify online)", "admission": "Library FREE; Eatopia food hall pay-as-you-go (lunch ~5,000-25,000 KRW per person)", "walking": "Easy — escalators and elevators between all floors; wheelchair/stroller accessible throughout"}, "convenience": {"restroom": "Multiple restrooms on every floor; family-friendly stations", "parking": "Underground ~5,000 spaces; first 3 hours FREE with mall purchase 30,000 KRW+; coach lot for groups"}, "smartNotes": {"photo": "**Library central atrium with 22-meter bookshelves** from 4F gallery looking down. **Vinyl Record Lounge** for retro aesthetic. **Cherry blossom installation in atrium (March-April)** — viral seasonal photo. Christmas tree (December). Children''s section on 4F for family photos.", "facilities": "Eatopia food hall B1F (30+ restaurants 5,000-40,000 KRW), Toy Kingdom 4F, Aquafield water park B1-2F, CGV + MEGABOX cinemas, free WiFi, multilingual customer service, tax-refund counters at major stores.", "tip": "**Library is FREE** during all mall hours. **22-meter bookshelves = Korea''s tallest library bookshelves** (mention to guests for impact). **Cherry blossom installation March-April** is the seasonal must-see. **Eatopia food hall for lunch** — pre-booking not required; visit during 13:00-13:30 to avoid Korean lunch peak. Avoid Saturday afternoons (peak crowd density). Verify Starfield monthly closure dates online before visit."}, "_poi_meta": {"poi_key": "starfield_library_suwon", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-05-21", "sources": ["Starfield official", "VisitKorea", "Shinsegae press", "BCHO Partners", "Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)", "Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)", "Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)", "ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review", "Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]}, "image": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "images": ["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"], "imageCredits": [{"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "location": "Starfield Suwon Library & Mall", "caption": "Starfield Suwon Library & Mall — photo 1", "alt": "Starfield Suwon Library & Mall — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "location": "Starfield Suwon Library & Mall", "caption": "Starfield Suwon Library & Mall — photo 2", "alt": "Starfield Suwon Library & Mall — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "location": "Starfield Suwon Library & Mall", "caption": "Starfield Suwon Library & Mall — photo 3", "alt": "Starfield Suwon Library & Mall — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp", "location": "Starfield Suwon Library & Mall", "caption": "Starfield Suwon Library & Mall — photo 4", "alt": "Starfield Suwon Library & Mall — gallery image 4"}]}, {"number": 4, "time": "≈ 15:30", "duration": "75 min", "name": "Waujeongsa Temple", "category": "Buddhist Temple (Modern Eclectic)", "description": "**Waujeongsa Temple (와우정사)** — **founded 1970 by Monk Kim Hae Geun (김해근)** as a refuge for North Korean Buddhist monks separated from their home temples after the Korean War (1950-1953) division of the peninsula. \n\nThe temple was originally established as ''Cheonsa-bul'' (literally ''Temple of a Thousand-and-One Buddhas'') in tribute to the 33-deity Buddhist pantheon multiplied across Korean reunification prayers. \n\n**Wau (와우, 臥牛)** = ''reclining cow'' — referencing the topography of nearby Yeonhwasan (Lotus Flower Mountain) which resembles a recumbent cow when viewed from a distance. \n\n**Jeong-sa (정사, 精舍)** = ''temple'' (Buddhist hermitage). The complete name therefore translates as ''Reclining Cow Temple.'' **One of Korea''s most architecturally distinctive Buddhist temples** — eclectic syncretic design incorporating elements from Buddhist traditions across India, Sri Lanka, Thailand, Myanmar (Burma), Tibet, China, and Korea. \n\nHosts ~3,000 Buddhist statues from various Asian Buddhist countries displayed across the grounds. **This is NOT a typical Korean Joseon-era temple** but a 1970-built reunification prayer temple — distinguish for guests. Signature features: the **12-meter-long, 3-meter-high wooden reclining Buddha (Wabul)** carved from a single Indonesian juniper tree — the **largest wooden reclining Buddha in the world** (Guinness World Records); the **8-meter outdoor Buddha head sculpture (Buldu, 불두)** at the temple entrance, made of bronze with gold-leaf coating, one of Korea''s tallest Buddha-head sculptures; the **3-meter sitting jade Buddha** carved from white jade imported from Myanmar — the largest jade Buddha in Korea; and **Bonzejeon Main Hall** housing an 8-meter Brass Buddha imported from Myanmar. \n\n**Bell of Unification (통일대종)** — a 12-ton bronze bell rung at the start of the 1988 Seoul Olympics, dedicated to Korean reunification; visitors can ring the bell (donations welcomed). \n\n**Indravarna Pagoda (인드라바르나탑)** in Sri Lankan style with white plaster exterior. **Stupa containing Buddha relics (sarira) gifted by Sri Lankan, Thai, and Myanmar Buddhist Orders** — a unique inter-Buddhist diplomatic gift. \n\n**FREE admission**. **Templestay program** available (overnight monk-led practice, traditional 108-bow practice, Seon meditation, Buddhist temple cuisine, traditional tea ceremony — reservations through templestay.com, ~70,000-90,000 KRW per night). \n\n**Best photographic seasons: spring cherry blossoms (April) and autumn foliage (October-November)** — golden ginkgo and red maple frame the temple buildings. \n\nThe temple grounds occupy a hillside with stairs between halls; ~500 m of walking with elevation gain.", "highlights": ["**Founded 1970 by Monk Kim Hae Geun as a Korean reunification prayer temple**", "Eclectic syncretic design — pan-Asian Buddhist (India, Sri Lanka, Thailand, Myanmar, Tibet, China, Korea)", "~3,000 Buddhist statues from various Asian Buddhist countries", "**12-meter-long, 3-meter-high wooden reclining Buddha = LARGEST in the world** (Indonesian juniper, Guinness World Records)", "**8-meter outdoor Buddha head sculpture** at temple entrance — Korea''s tallest", "**3-meter jade Buddha** = largest in Korea", "Bell of Unification = 12-ton bronze bell (rung at 1988 Seoul Olympics), for Korean reunification", "Buddha relics (sarira) gifted by Sri Lankan/Thai/Myanmar Orders", "**FREE admission** + Templestay program available", "Spring cherry blossoms / autumn foliage — photographic peak"], "timeUsed": ["30-min coach drive from Starfield Suwon to Yongin''s Waujeongsa", "Brief group orientation at temple entrance (~5 min)", "Self-guided walk: Buddha head → main halls → reclining Buddha → bell → pagoda (~50-60 min)", "Reassembly at coach (~10 min)", "Optional Bell of Unification (12-ton bronze, rung at 1988 Seoul Olympics) striking with reunification wish (donations welcomed; ~10 min)"], "whyOnRoute": "Tour 3''s mountain-temple finish — peaceful spiritual contrast to Hwaseong''s military architecture and Starfield''s commercial modernity. **Distinct positioning from typical Korean temples**: Waujeongsa is a 1970-built syncretic pan-Asian Buddhist eclectic temple (NOT a Joseon-era traditional temple) — which makes it a more visually striking and tourist-accessible experience than mountain-locked traditional temples. **FREE admission** keeps the tour budget-friendly. Yongin''s Yeonhwasan setting + ~30 min drive from Starfield positions it as a coherent westward-extension to the day''s loop before evening return. Closing the day at Waujeongsa shifts register from Joseon-secular (Hwaseong) and 21st-century-commercial (Starfield) to **20th-century Buddhist-syncretic** — the 1970-founded reunification-prayer temple''s eclectic syncretism (Indian sandalwood reclining Buddha + Sri Lankan-style Indravarna pagoda + Burmese-imported brass and white-jade Buddhas + Sri Lankan/Thai/Myanmar Buddhist relic gifts) is unlike any older Korean temple, making it a fitting evening-hours contemplative anchor before the return to Seoul. **Admission is FREE** (donations welcome at the main hall). By car: ~50-60 min from Starfield Suwon via Yongin direction. Best photographic season: **Spring (April-May) cherry blossoms** or **Autumn (October-November) ginkgo + maple foliage framing the temple buildings**.", "visitBasics": {"hours": "Daily 06:00-19:00 (visitor halls typically 09:00-18:00)", "closed": "Open year-round", "admission": "**FREE** (donations welcomed); Templestay overnight ~70,000-90,000 KRW", "walking": "Moderate — temple grounds on a hillside with stairs between halls; ~500 m of walking with elevation gain"}, "convenience": {"restroom": "Near main hall and visitor information area", "parking": "Free parking at temple entrance lot; tour coaches accommodated"}, "smartNotes": {"photo": "**8-meter Buddha head (Buldu)** at the entrance — the iconic Waujeongsa shot, especially with autumn foliage backdrop. **3-meter wooden reclining Buddha** inside the main hall (the world''s largest wooden reclining Buddha). **Indravarna Pagoda** in Sri Lankan style. Buddha statues from across Asia in the courtyards. **Cherry blossoms (April) or autumn foliage (October-November)** make the temple a photographer''s destination.", "facilities": "Visitor information center, Templestay registration office, monks'' robes for purchase, prayer beads and Buddhist items shop, vegetarian temple-cuisine canteen (lunch ~10,000 KRW). Yeonhwasan Mountain hiking trails behind the temple (4 km loop, ~1.5 hr).", "tip": "**FREE admission** — exceptional value vs. other major Korean temples. **Distinct from traditional temples** — explain to guests this is NOT a Joseon-era temple but a **1970-built eclectic pan-Asian reunification prayer temple**. **Best photographic seasons**: spring cherry blossoms (April) or autumn foliage (late October-early November). Wear modest clothing (covered shoulders + knees). The 8-meter Buddha head at the entrance is the universally agreed iconic photo. **Templestay program** is a unique experience for guests with extra time — pre-booking via templestay.com required."}, "_poi_meta": {"poi_key": "waujeongsa_temple", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-04-29", "sources": ["VisitKorea", "Wikipedia", "Visit Yongin", "Templestay Korea", "Korea Tourism Organization (english.visitkorea.or.kr — Waujeongsa Temple official listing)", "Visit Yongin Tourism (yongin.go.kr/tour — Kim Hae Geun 1970 founding + reunification prayer temple)", "Templestay Korea (templestay.com — Waujeongsa overnight program + 108-bow practice + sachal eumsik cuisine)", "Wikipedia (Waujeongsa — pan-Asian Buddhist syncretism + Indravarna pagoda + Bell of Unification 12-ton (1988 Seoul Olympics))", "Korea Buddhism Yeonhwasan/Lotus-Mountain regional guide (Waujeongsa 와우 = ''reclining cow'' + Indonesian juniper reclining Buddha origin (Guinness World Records))"]}, "image": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp", "images": ["/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp", "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp", "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp", "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp", "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp"], "imageCredits": [{"url": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp", "source": "atoc-korea"}, {"url": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp", "source": "atoc-korea"}, {"url": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp", "source": "atoc-korea"}, {"url": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp", "source": "atoc-korea"}, {"url": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp", "location": "Waujeongsa Temple", "caption": "Waujeongsa Temple — photo 1", "alt": "Waujeongsa Temple — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp", "location": "Waujeongsa Temple", "caption": "Waujeongsa Temple — photo 2", "alt": "Waujeongsa Temple — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp", "location": "Waujeongsa Temple", "caption": "Waujeongsa Temple — photo 3", "alt": "Waujeongsa Temple — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp", "location": "Waujeongsa Temple", "caption": "Waujeongsa Temple — photo 4", "alt": "Waujeongsa Temple — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp", "location": "Waujeongsa Temple", "caption": "Waujeongsa Temple — photo 5", "alt": "Waujeongsa Temple — gallery image 5"}]}], "routeFlowStops": [{"name": "Hwaseong", "type": "origin", "theme": "UNESCO Past"}, {"name": "Hwaseong Haenggung Palace", "type": "primary", "theme": "Heritage Palace"}, {"name": "Starfield Library", "type": "primary", "theme": "Modern Korea"}, {"name": "Lunch", "type": "meal", "theme": "Reset"}, {"name": "Waujeongsa", "type": "return", "theme": "Spiritual Close"}], "routePhases": [{"phase": "UNESCO Heritage", "duration": "Stops 1", "description": "Morning: UNESCO Heritage"}, {"phase": "Library & Lunch", "duration": "Stops 2–3", "description": "Midday: Library & Lunch"}, {"phase": "Mountain Temple Finish", "duration": "Stops 4", "description": "Afternoon: Mountain Temple Finish"}], "routeShapeIntro": {"title": "How this day moves", "subtitle": "Pickup at one of two Seoul meeting points (typically Hongik University Station or Myeongdong) around 09:00, then UNESCO heritage in the morning, contemporary library and lunch midday, and a peaceful temple close in Yongin. Return to Seoul around 18:00 to 19:00."}, "whyTourWorks": {"bestFor": ["First-time visitors to Korea wanting heritage + modern in one day", "History-leaning travelers and UNESCO completists", "Photographers (Hwaseong walls, Starfield atrium, Buddha statues)", "Couples and adult families looking for a balanced rather than active day", "Travelers who want a small-group format with included admission"], "routeLogicSections": [{"title": "Why this Suwon-Yongin route works", "icon": "landmark", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "items": [{"label": "Three eras in one day", "detail": "Joseon-era UNESCO architecture, contemporary Korean lifestyle, and a mountain Buddhist temple cover three very different sides of Korean culture without doubling back."}, {"label": "Tight geography", "detail": "Hwaseong, Starfield Suwon, and Waujeongsa all sit within a 30-minute drive of each other south of Seoul, so transit time stays manageable."}, {"label": "Stronger value than a Hwaseong-only trip", "detail": "Adding Starfield and the temple turns a single-attraction visit into a fuller day-trip without a major price jump."}]}, {"title": "How the walking load actually feels", "icon": "footprints", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "Hwaseong is the most active section", "detail": "The wall walk is the route''s main physical demand, with stone steps and uneven surfaces. Most travelers handle it fine in good shoes."}, {"label": "Starfield is rest time", "detail": "The library and lunch break is essentially indoor walking and seated time, which gives the route a useful midday recovery."}, {"label": "Waujeongsa is moderate", "detail": "The temple grounds involve some uphill walking and stairs, but each section is short and the main Buddha statue is reachable from the entrance."}]}, {"title": "Weather notes", "icon": "cloud-rain", "iconBg": "bg-slate-50/80", "iconColor": "text-slate-600", "items": [{"label": "Hwaseong is the most weather-sensitive stop", "detail": "Heavy rain or snow makes the wall walk less comfortable; the Haenggung indoor palace is a good alternative on bad-weather days."}, {"label": "Starfield is full weather buffer", "detail": "The library and mall are fully indoor, so this stop is a useful rainy-day anchor."}, {"label": "Summer humidity affects the day", "detail": "The fortress wall and temple grounds are exposed; bring water and sun protection between June and August."}]}], "lessIdealFor": ["Travelers wanting a shopping-heavy mall day", "Visitors who dislike walking on stone walls or temple paths", "Anyone needing a fully fixed-pace day with no walking", "Travelers wanting to visit Seoul''s central palaces (this trip stays outside Seoul)"]}, "practicalAccordionItems": [{"id": "pickup", "title": "Pickup & drop-off", "preview": "Two Seoul meeting points; ≈09:00 departure", "content": ["Pickup typically from Hongik University Station (Exit 4) and Myeongdong Station", "Departure typically around 08:30 to 09:00 from the first meeting point", "Please arrive at least 10 minutes early at your selected meeting point", "Drop-off at the same Seoul meeting points", "Expected return between 18:00 and 19:00 depending on traffic and Sunday delays", "This is a fixed-route group format, not hotel pickup; travelers must reach the meeting point themselves"]}, {"id": "walking", "title": "Walking & terrain", "preview": "Moderate; the Hwaseong wall is the main physical section", "content": ["Hwaseong Fortress: stone steps along the wall walk and at the main gates; uneven historic surfaces", "Starfield Library and Mall: easy indoor walking on flat floors", "Waujeongsa Temple: moderate with some uphill paths and stairs", "Comfortable walking shoes with grip are recommended", "Stroller use is possible at Starfield only; Hwaseong walls and Waujeongsa are not stroller-friendly"]}, {"id": "weather", "title": "Weather policy", "preview": "Light rain workable; heavy rain reduces the fortress walk", "content": ["Light rain: tour usually proceeds with normal adjustments", "Heavy rain or snow: the Hwaseong wall walk may be shortened in favor of Hwaseong Haenggung Palace", "Starfield is a fully indoor stop and works as a wet-weather anchor", "Waujeongsa is partially exposed; temple operations continue in light rain"]}, {"id": "wear", "title": "What to wear & bring", "preview": "Walking shoes, modest temple clothing, layers", "content": ["Comfortable walking shoes with grip (essential for Hwaseong and Waujeongsa)", "Modest clothing for the temple visit (covered shoulders recommended)", "Light layers for changing temperatures between exposed walls and indoor spaces", "Sun protection and water in summer", "Camera or phone with wide-angle for Starfield Library shots"]}, {"id": "included", "title": "What''s included", "preview": "Guide, transport, and admission included; lunch pay direct", "variant": "included", "content": ["Professional English-speaking guide", "Round-trip transport from Seoul (small-group vehicle)", "All admission fees (Hwaseong, Hwaseong Haenggung, Starfield is free, Waujeongsa)", "Lunch is not included; pay directly at Starfield mall restaurants", "Personal shopping is not included", "Optional cafe purchases are not included", "Guide gratuities are optional"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "Live weather integration"}, "tomorrow": {"temp": "—", "label": "Updated daily"}}, "seasonalVariations": [{"season": "Spring", "title": "Cherry blossom season", "description": "Cherry blossoms line the Hwaseong wall in early April, making this one of the best photo seasons for the route.", "icon": "flower"}, {"season": "Summer", "title": "Lush but humid", "description": "Lush green temple grounds and longer daylight, but humidity and exposed-wall heat make the morning section feel more demanding.", "icon": "sun"}, {"season": "Autumn", "title": "Best all-round season", "description": "Crisp visibility and foliage along the Hwaseong wall and Yeonhwasan; one of the strongest all-round seasons for the route.", "icon": "leaf"}, {"season": "Winter", "title": "Quiet and dramatic", "description": "Quiet temple grounds and dramatic fortress walls; cold but visually rewarding. Bundle up because the wall walk is exposed.", "icon": "snowflake"}], "bookingTrustItems": [{"icon": "check-circle", "title": "Licensed local operator", "description": "Authorized Korean tour operator with full insurance", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600"}, {"icon": "route", "title": "Route specialists", "description": "Hand-tuned itinerary, not a generic loop", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600"}, {"icon": "users", "title": "Curated group size", "description": "Right-sized for the route", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600"}], "bookingSupportSteps": [{"timing": "Immediately", "title": "Instant Confirmation", "detail": "Booking confirmation with itinerary summary"}, {"timing": "12 hours before", "title": "12-Hour Reminder", "detail": "Weather update and any route adjustments"}, {"timing": "Evening before", "title": "Final Pickup Info", "detail": "Exact pickup time and driver contact"}, {"timing": "Morning of tour", "title": "Day-of Route Notes", "detail": "Morning briefing based on live conditions"}, {"timing": "During tour", "title": "Stop-by-Stop Tips", "detail": "Real-time guidance at each location"}, {"timing": "After tour", "title": "Post-tour Support", "detail": "Follow-up and recommendations"}], "staticQuestions": [{"id": "q1", "question": "How is this different from the Suwon + Folk Village or Suwon + Gwangmyeong Cave tours?", "answer": "All three share Suwon Hwaseong Fortress + Hwaseong Haenggung Palace + Starfield Library. This version adds Waujeongsa Temple in Yongin (Buddhist, 3,000+ statues, world''s largest wooden reclining Buddha). The Folk Village version adds Korean Folk Village (270+ traditional houses, K-drama filming). The Gwangmyeong version adds the underground LED-lit cave park. Pick this one if Buddhist sculpture interests you most; the Folk Village version for deepest heritage; Gwangmyeong for variety and indoor weather."}, {"id": "q2", "question": "Are admissions included?", "answer": "Yes — all three paid stops are included: Suwon Hwaseong Fortress (1,000 KRW adult), Hwaseong Haenggung Palace (1,500 KRW adult), and Waujeongsa Temple (free admission). Starfield Library is also free for everyone. Optional café drinks, mall food hall meals, and any souvenir purchases are at your own cost."}, {"id": "q3", "question": "Is lunch included?", "answer": "No. Lunch is during free time at Starfield Suwon''s mall food hall — large variety, casual seating, typically 10,000-20,000 KRW per person. The library and mall are stop #2 (≈13:30 arrival) so the timing works as a natural break between Hwaseong in the morning and Waujeongsa in the afternoon."}, {"id": "q4", "question": "What''s distinctive about Waujeongsa Temple?", "answer": "It''s a non-traditional temple: founded in 1970 by Monk Kim Hae-Geun (a North Korean refugee) and built around a single founder''s collection of 3,000+ Buddha statues from across Asia. The headline pieces are the Buldu — an 8-meter wooden Buddha head registered in the Guinness Book of Records as the world''s largest — and the Wabul, a 3m × 12m wooden reclining Buddha carved from an Indonesian juniper. The 12-ton Bell of Unification was rung at the start of the 1988 Seoul Olympics. Free admission, ≈75 minutes recommended."}, {"id": "q5", "question": "Do I need to dress modestly for the temple?", "answer": "Covered shoulders are recommended at Waujeongsa — bring a light layer if wearing a sleeveless top in summer. Hats are typically removed inside the main halls. No strict dress code is enforced for outdoor temple grounds, but modest clothing is appreciated as a sign of respect. Comfortable walking shoes with grip help with the temple''s stairs and inclines."}, {"id": "q6", "question": "How is the walking load distributed across the day?", "answer": "Three different walking styles: Hwaseong Fortress wall has the hardest section (steep gradients, stairs at gates, ≈1 km walked); Starfield Library is fully indoor with escalators; Waujeongsa has stairs and inclines on temple grounds (moderate). Total walking ≈3-4 km across the day. Comfortable shoes essential, especially for the wall walk and temple paths."}, {"id": "first-time", "question": "Is this a good choice for first-time visitors to Suwon & Yongin?", "answer": "Yes — this is one of the strongest first-time picks for travelers who want one UNESCO heritage site, one contemporary photo space, and one distinctive Buddhist temple in a single guided day. The format keeps things balanced rather than active, with all stops geographically close (Suwon-Yongin corridor, ≈30 min apart). Free hotel pickup from Hongdae or Myeongdong simplifies the morning logistics."}, {"id": "walking", "question": "Is the walking difficult?", "answer": "Moderate active walking. The hardest section is Hwaseong Fortress: ≈1 km of stone wall walk with steep gradients, stairs at gates, and uneven historic surfaces — comfortable shoes with grip essential. Starfield Library is easy indoor walking on flat floors. Waujeongsa Temple has some uphill paths and stairs (moderate). Total walking ≈3-4 km across the day. Strollers difficult on the wall and temple, fine at Starfield."}, {"id": "family", "question": "Is this tour suitable for families?", "answer": "Yes — comfortable for most families with children age 6+. Strollers are challenging on the Hwaseong wall and at Waujeongsa, but Starfield is fully stroller-friendly with escalators and elevators. Kids often respond strongly to Waujeongsa''s giant Buddha head and the 3,000+ statue collection. Hanbok rental at Hwaseong Haenggung Palace is a popular family photo moment (and gets free fortress admission)."}, {"id": "seniors", "question": "Can older adults join comfortably?", "answer": "Yes for active seniors comfortable with stairs and uneven ground; more limited for low-mobility travelers. The Hwaseong wall walk has the hardest sections (steep gradients, stone steps); seniors can walk the easier flat segments and skip the climb to command posts. Waujeongsa has temple-ground stairs but the main statue collection is on accessible levels. Starfield is fully escalator/elevator-accessible — the recovery stop."}, {"id": "children", "question": "What''s the recommended minimum age?", "answer": "Best fit is around age 6 and up. The fortress wall has stairs and uneven historic surfaces, and Waujeongsa''s temple grounds have inclines that tire very young children. Older kids do well — the giant Buddha head and the Bell of Unification have a ''wow'' factor and Starfield''s library is accessible. Strollers manage well at Starfield but not on the wall."}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"star