  full_document = '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library", "locale": "en", "product_id": "seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library", "seo": {"pageTitle": "Suwon Hwaseong, Gwangmyeong Cave & Starfield Tour | AtoC Korea", "metaDescription": "9-hour small-group day tour from Seoul: UNESCO Suwon Hwaseong Fortress, Hwaseong Haenggung, Starfield Library, LED-lit Gwangmyeong Cave.", "primaryKeywords": ["Suwon Hwaseong tour from Seoul", "Gwangmyeong Cave day trip", "Starfield Library Suwon tour", "UNESCO Korea day tour"], "ogImage": "https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "title": "Suwon Hwaseong, Gwangmyeong Cave & Starfield Library Day Tour from Seoul | AtoC Korea"}, "catalog_card": {"thumbnail": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "title": "Suwon: Hwaseong, Gwangmyeong Cave & Starfield", "priceLabel": "From US$53 per person (was $59, 10% off)", "shortCardDescription": "A small-group cultural day-trip from Seoul covering three contrasting sides of Gyeonggi Province: the UNESCO-listed Suwon Hwaseong Fortress with its 18th-century walls and Haenggung Palace, the dramatic LED-lit underground theme park inside Gwangmyeong Cave (a former Japanese-era gold mine), the four-floor Starfield Library Suwon. 9 hours with included transport and admissions.", "tags": ["small_group", "culture", "unesco", "cave", "library", "shopping", "day_trip"], "rating": 0, "reviewCount": 0, "slug": "seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library", "subtitle": "A small-group cultural day-trip from Seoul covering four contrasting sides of Gyeonggi Province: the UNESCO-listed Suwon Hwaseong Fortress with its…", "region": "Gyeonggi-do (south of Seoul)", "duration": "9 hours", "stopsCount": 6, "badges": ["Small Group", "Culture", "UNESCO", "Cave", "Library", "Shopping", "Day Trip"], "heroImage": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp"}, "headlineLine1": "Suwon Heritage Day", "headlineLine2": "Hwaseong, Gwangmyeong Cave & Starfield", "price": {"amountLabel": "53", "currency": "USD", "per": "person", "salePriceUsd": 53, "originalPriceUsd": 59, "discountPercent": 10}, "hero": {"imageUrl": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "imagePosition": "center 35%", "tagline": "Korea''s only walled fortress city built with its original Uigwe records, a former gold mine reborn as art, and the country''s most-photographed library", "pills": ["Small Group", "Culture"], "meta": {"duration": "9 hours", "region": "Gyeonggi-do (south of Seoul)", "stops": "6 stops", "rating": 0, "ratingStars": 0}}, "subnavItems": [{"id": "overview", "label": "Overview"}, {"id": "itinerary", "label": "Itinerary"}, {"id": "details", "label": "Details"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "Reviews"}], "glanceItems": [{"icon": "camera", "label": "Photo Value", "value": "Excellent", "level": 5}, {"icon": "mountain", "label": "Scenic", "value": "Good", "level": 4}, {"icon": "footprints", "label": "Walking", "value": "High", "level": 4}, {"icon": "cloud-rain", "label": "Rain Safety", "value": "Excellent", "level": 5}, {"icon": "users", "label": "Family Fit", "value": "Good", "level": 4}, {"icon": "gauge", "label": "Balance", "value": "Balanced", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 1", "caption": "Suwon Hwaseong Fortress — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "location": "Starfield Library Suwon", "alt": "Starfield Library Suwon — gallery image 1", "caption": "Starfield Library Suwon — photo 1"}, {"id": 3, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp", "location": "Gwangmyeong Cave", "alt": "Gwangmyeong Cave — gallery image 1", "caption": "Gwangmyeong Cave — photo 1"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 2", "caption": "Suwon Hwaseong Fortress — photo 2"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 3", "caption": "Suwon Hwaseong Fortress — photo 3"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 4", "caption": "Suwon Hwaseong Fortress — photo 4"}, {"id": 7, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 5", "caption": "Suwon Hwaseong Fortress — photo 5"}, {"id": 8, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Suwon Hwaseong Fortress", "alt": "Suwon Hwaseong Fortress — gallery image 6", "caption": "Suwon Hwaseong Fortress — photo 6"}, {"id": 9, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "location": "Starfield Library Suwon", "alt": "Starfield Library Suwon — gallery image 2", "caption": "Starfield Library Suwon — photo 2"}, {"id": 10, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "location": "Starfield Library Suwon", "alt": "Starfield Library Suwon — gallery image 3", "caption": "Starfield Library Suwon — photo 3"}, {"id": 11, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp", "location": "Starfield Library Suwon", "alt": "Starfield Library Suwon — gallery image 4", "caption": "Starfield Library Suwon — photo 4"}, {"id": 12, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp", "location": "Gwangmyeong Cave", "alt": "Gwangmyeong Cave — gallery image 2", "caption": "Gwangmyeong Cave — photo 2"}, {"id": 13, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp", "location": "Gwangmyeong Cave", "alt": "Gwangmyeong Cave — gallery image 3", "caption": "Gwangmyeong Cave — photo 3"}, {"id": 14, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp", "location": "Gwangmyeong Cave", "alt": "Gwangmyeong Cave — gallery image 4", "caption": "Gwangmyeong Cave — photo 4"}], "itineraryStops": [{"number": 1, "time": "≈ 08:30", "duration": "10 min", "name": "Seoul departure", "category": "Pickup & departure", "description": "Pickup from one of two central Seoul meeting points: **Hongik University Station Exit 8** (Hongdae area, Seoul Subway Line 2/Airport Express) or **Myeongdong Station Exit 2 or 4** (Seoul Subway Line 4). About **1 hour by coach south to Suwon** via the Gyeongbu Expressway. \n\nThe 9-hour day is structured to start at Hwaseong Fortress (UNESCO 1997) before crowds peak around 11:00, then enjoy lunch at the mid-afternoon Starfield Library, and close with Gwangmyeong Cave''s LED-art finale before evening return. Coach is air-conditioned and equipped with USB charging at most seats.", "highlights": ["Pickup from Hongik University (Line 2) or Myeongdong (Line 4) ~08:30", "1-hour coach south to Suwon via Gyeongbu Expressway", "9-hour day designed to clear Hwaseong before crowds peak", "Coach with air conditioning + USB charging"], "timeUsed": ["Meet at designated Seoul pickup point (~5 min for boarding)", "1-hour coach drive to Suwon (~60 min in light traffic)"], "whyOnRoute": "An 09:30 Suwon arrival puts the group at Hwaseong Fortress with 60-90 min before midday crowds peak around 11:00. The day''s clockwork — fortress → palace → market lunch → library → cave — minimizes coach repositioning and ends with the cave''s reliable indoor finale.", "visitBasics": {}, "convenience": {}, "smartNotes": {"tip": "Confirm exact pickup time and meeting point at booking. Bring water, sunscreen, and comfortable shoes for fortress wall walking — and a light jacket for the cave (12°C year-round)."}, "_poi_meta": {"poi_key": "OPS_seoul_pickup_default", "verified": false, "match": "operational_default", "kb_version": "v1.14", "verified_date": "2026-04-29", "note": "Operational pickup — Seoul departure"}, "_role": "pickup"}, {"number": 2, "time": "≈ 09:30", "duration": "60 min", "name": "Suwon Hwaseong Fortress", "category": "UNESCO Fortress", "description": "**Suwon Hwaseong (수원화성) — UNESCO World Heritage Site since 1997** — Korea''s only walled fortress city preserved with its original 10-volume construction record (Hwaseong Seongyeok Uigwe, separately inscribed on the UNESCO Memory of the World Register in 2007). Built **1794-1796 in 2 years 9 months** under King Jeongjo (정조, 22nd Joseon king, r. \n\n1776-1800) — the king''s project to relocate the Joseon capital from Hanyang (Seoul) to Suwon and to honor his executed father Crown Prince Sado. Designed by **Jeong Yak-yong (정약용, Dasan)** — Joseon''s leading scholar-engineer of the Silhak (practical learning) school — who integrated Korean defensive architecture with Chinese siege defense theory and emerging Western fortification science. \n\nJeong Yak-yong invented the **geojunggi (거중기) pulley-and-block crane** — the first documented use of Western-style modern engineering in Korean construction. \n\n**5.74 km wall circumference, 41 strategic structures**, including **Janganmun (north main gate) — the LARGEST EXISTING ROYAL GATE IN KOREA**, larger than Seoul''s Sungnyemun. \n\nThe 9-hour-day route walks the **most photogenic 1.2 km section between Janganmun and Hwaseomun (west gate, National Treasure No. 403)** — ~25-30 min walking through the highest density of preserved military structures. \n\n**Hwahongmun (north sluice gate)** with its 7 arches over Suwoncheon Stream is the most photographed structure. **FREE for hanbok-wearers + last Wed of month + seniors 65+ + children ≤6** — a meaningful budget item across a Suwon family day.", "highlights": ["**UNESCO World Heritage Site since 1997** — Korea''s only walled fortress city with original construction records", "Built 1794-1796 in 2 years 9 months under King Jeongjo", "Designed by Jeong Yak-yong using Korean + Chinese + Western fortification science", "Hwaseong Seongyeok Uigwe — UNESCO Memory of the World 2007", "5.74 km circumference, 41 strategic military structures", "Janganmun north gate — **largest existing royal gate in Korea**", "1.2 km guided walk Janganmun → Hwaseomun (highest photo-density section)", "Hwahongmun 7-arch sluice gate — most photographed structure", "FREE for hanbok-wearers + seniors 65+ + last Wed of month"], "timeUsed": ["Coach drop-off near Janganmun (~5 min)", "Brief group orientation (~5 min)", "Walk Janganmun → Hwaseomun (~25-30 min)", "Photo time + reassembly at vehicle (~10 min)", "Optional Hwaseong Yeolcha sightseeing trolley Yeonmudae↔Paldalmun (~30 min one-way; ₩4,000 adult)"], "whyOnRoute": "The route''s UNESCO anchor — Korea''s only remaining walled fortress city, built 1794-1796 under King Jeongjo. The Janganmun → Hwaseomun walk gives the highest density of preserved military structures in a 60-min stop, sized for a 9-hour day with 5 substantive stops. The full 5.74 km loop would consume 2.5+ hours and cannibalize the day''s other heritage and modern stops. For this 5-stop itinerary, Hwaseong serves as the **morning anchor** — the 5.74 km perimeter is too long to circumnavigate in a single visit, so the day-trip format focuses on the Janganmun → Seojangdae western section (~25-30 min walking, highest preservation density). The 1801 **Hwaseong Seongyeok Uigwe** construction record — UNESCO Memory of the World since 2007 — documented every stone, beam, and laborer''s wage, enabling faithful 1975-onwards reconstruction after Korean War damage. Jeong Yak-yong''s **Geojunggi (거중기) pulley-and-block crane** is the world''s first documented use of Western mechanical-advantage engineering on a Joseon-era construction site, predating Korea''s industrial mechanization by ~120 years.", "visitBasics": {"hours": "Wall path 24 hours; recommended 09:00-18:00 summer / 09:00-17:00 winter", "closed": "Open year-round (Hwaseong Trolley closed Mondays)", "admission": "Adults 1,000 / Youth 700 / Children 500 KRW (FREE: children ≤6, seniors 65+, hanbok-wearers, last Wed of month)", "walking": "Moderate — wall has steep sections; stairs at gates"}, "convenience": {"restroom": "At Janganmun, Hwaseomun, Paldalmun, Yeonmudae", "parking": "Coach drop-off at Janganmun lot"}, "smartNotes": {"photo": "**Hwahongmun (north sluice gate)** with 7 arches over Suwoncheon Stream — the iconic shot. **Janganmun (largest existing royal gate in Korea)** at golden hour. **Seojangdae (west command post)** sunset over Paldalsan Mountain.", "facilities": "Visitor Information Centers at all main gates; English-Korean signage throughout", "tip": "Hanbok rental at Haenggung Square gives FREE fortress + palace admission. The Janganmun → Hwaseomun section gives the highest per-meter heritage density."}, "_poi_meta": {"poi_key": "hwaseong_fortress", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-04-29", "sources": ["UNESCO WHC", "VisitKorea", "Suwon CVB", "UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)", "Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)", "Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)", "Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)", "Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]}, "image": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "images": ["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "/images/tours/suwon-hwaseong/photo-002.webp"], "imageCredits": [{"url": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/photo-002.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 1", "alt": "Suwon Hwaseong Fortress — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 2", "alt": "Suwon Hwaseong Fortress — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 3", "alt": "Suwon Hwaseong Fortress — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 4", "alt": "Suwon Hwaseong Fortress — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 5", "alt": "Suwon Hwaseong Fortress — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Suwon Hwaseong Fortress", "caption": "Suwon Hwaseong Fortress — photo 6", "alt": "Suwon Hwaseong Fortress — gallery image 6"}]}, {"number": 3, "time": "≈ 10:45", "duration": "60 min", "name": "Hwaseong Haenggung Palace", "category": "Joseon Royal Detached Palace", "description": "**Hwaseong Haenggung (화성행궁) — Korea''s largest existing haenggung (detached palace)** — built 1789-1796 alongside the Hwaseong fortress walls under King Jeongjo. \n\nA **haenggung** is a temporary/detached royal residence used during travel, war refuge, or special ceremonies; Hwaseong Haenggung surpasses Onyang, Bukhansan, and Namhansan haenggung in scale. King Jeongjo built it primarily to stay overnight when visiting his executed father Crown Prince Sado''s tomb (Hyeollyungwon, now Yungneung Royal Tomb, 4 km south) — a pilgrimage made **13 times during his reign**. \n\nThe most famous was the **1795 royal procession** (6,000 attendants + 1,400 horses) celebrating Lady Hyegyeong''s 60th birthday — documented in the **Wonhaeng Eulmyo Jeongni Uigwe, UNESCO Memory of the World since 2007**. Originally **576 kan (rooms/structural bays)** — a complete miniature royal palace. \n\nLargely destroyed during Japanese colonial period (1910-1945) when converted into Suwon Provincial Hospital and Police Station. Restoration began 1996; first phase complete 2003 (Bongsudang, Naknamheon, Janganheon, Yuyeotaek), second phase 2009 (Wuhwagwan royal kitchen, Sinpungnu gate). \n\n**Critical historical note: Naknamheon (낙남헌) is the ONLY building that survived from the original 1796 construction** — Japanese converted it into Police Station offices but did not demolish it. It is therefore the only AUTHENTIC original structure on the site; everything else is post-1996 reconstruction. \n\n**Royal Guard Changing Ceremony** at Sinpungnu Gate — **Tuesday-Sunday 11:00 AM**, ~15 min, FREE. The route''s 10:45 arrival is timed for the 11:00 ceremony when day-of-week permits. Filmed for K-drama **''Jewel in the Palace'' (Daejanggeum, 2003)** — the iconic Joseon hit (peak ratings around 57% in Korea).", "highlights": ["**Korea''s largest existing haenggung (detached palace)** — originally 576 rooms", "King Jeongjo''s 13 royal pilgrimages here to honor his executed father Crown Prince Sado", "**Naknamheon = ONLY original 1796 structure remaining** (others reconstructed)", "**Royal Guard Changing Ceremony Tue-Sun 11:00 AM at Sinpungnu Gate (FREE)**", "1795 Royal Procession — UNESCO Memory of the World", "K-drama ''Jewel in the Palace'' filming location", "FREE for hanbok-wearers + seniors 65+", "**Naknamheon (낙남헌) is the ONLY building surviving from the original 1796 construction** — Japanese colonial-era authorities converted it into Police Station offices but did not demolish it; every other Haenggung structure visible today is a post-1996 reconstruction following the Hwaseong Seongyeok Uigwe (UNESCO Memory of the World since 2007)", "**576 kan (rooms/structural bays)** = the LARGEST surviving haenggung detached-palace in Korea — King Jeongjo built it specifically to overnight when visiting his executed father Crown Prince Sado''s tomb (Hyeollyungwon, 4 km south); Jeongjo made the journey 13 times between 1795-1800"], "timeUsed": ["5 min walk from Hwaseong Fortress (Hwaseomun area)", "Royal Guard Changing Ceremony at 11:00 (Tue-Sun) — ~15 min", "Bongsudang + Naknamheon + Janganheon walk (~30 min)", "Photo time + reassembly at vehicle (~10 min)", "Optional Royal Guard Changing Ceremony at Sinpungnu Gate (Tue-Sun 11:00 AM, ~15 min, FREE — weather permitting)"], "whyOnRoute": "The temporary royal residence is INSIDE the same UNESCO site as Hwaseong Fortress, 5 min walk apart. **Naknamheon = the only authentic original structure** (others rebuilt post-1996). Time arrival for the 11:00 AM Royal Guard Changing Ceremony — FREE, 15 min, one of the catalog''s strongest free-experience hooks. Haenggung occupies the **historical and emotional center** of the Hwaseong project — the fortress walls were built around it (1794-1796) precisely to defend King Jeongjo''s filial-piety pilgrimages to his father''s tomb. Visiting Haenggung after the wall stretch converts an abstract military-architecture lesson into lived royal-Joseon spatial experience: the same **Bongsudang throne hall** also hosted the lavish 60th-birthday banquet for Jeongjo''s mother Lady Hyegyeong in 1795 (depicted in the surviving Uigwe Banchado court-painting scrolls). The site has appeared in numerous K-dramas including Jewel in the Palace (2003), Sungkyunkwan Scandal (2010), and Moonlight Drawn by Clouds (2016). A **Combined Fortress + Haenggung ticket** at 3,500 KRW (vs 2,500 KRW separately) makes Haenggung a high-value addition to the day''s anchor sequence.", "visitBasics": {"hours": "09:00-18:00 (last entry 17:30); summer May-Oct evening hours 18:00-21:00", "closed": "Open year-round", "admission": "Adult 1,500 / Teen 1,000 / Child 700 KRW. Combined Fortress + Haenggung 3,500 KRW. FREE for hanbok-wearers, seniors 65+", "walking": "Easy — palace grounds mostly flat with some steps between courtyards"}, "convenience": {"restroom": "At main entrance, near Bongsudang, at Haenggung Square", "parking": "Hwaseong Haenggung public parking; Haenggung Square paid lots"}, "smartNotes": {"photo": "**Bongsudang Main Hall** + **Naknamheon (the only original 1796 structure)** + **Royal Guard Changing Ceremony at Sinpungnu (Tue-Sun 11:00 AM)**.", "facilities": "Visitor Information Center, hanbok rental at Haenggung Square (15,000-20,000 KRW for 4 hr), Suwon Tongdak restaurants 5 min walk south.", "tip": "**Time arrival for 11:00 AM Royal Guard Changing Ceremony Tue-Sun (FREE)**. **Naknamheon is THE single most historically important spot** — the only structure not rebuilt, surviving Japanese colonial demolition. Skip Mondays — Royal Guard Changing Ceremony performed Tue-Sun only."}, "_poi_meta": {"poi_key": "hwaseong_haenggung", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-04-29", "sources": ["VisitKorea", "Wikipedia", "Suwon CVB", "Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)", "Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)", "Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)", "Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)", "Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]}, "image": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "images": ["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "/images/tours/suwon-hwaseong/photo-002.webp"], "imageCredits": [{"url": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/suwon-hwaseong/photo-002.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 1", "alt": "Hwaseong Haenggung Palace — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 2", "alt": "Hwaseong Haenggung Palace — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 3", "alt": "Hwaseong Haenggung Palace — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 4", "alt": "Hwaseong Haenggung Palace — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 5", "alt": "Hwaseong Haenggung Palace — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/suwon-hwaseong/photo-002.webp", "location": "Hwaseong Haenggung Palace", "caption": "Hwaseong Haenggung Palace — photo 6", "alt": "Hwaseong Haenggung Palace — gallery image 6"}]}, {"number": 4, "time": "≈ 12:30", "duration": "90 min", "name": "Starfield Library Suwon", "category": "Modern Cultural Landmark", "description": "**Starfield Library Suwon (별마당 도서관 수원)** — inside **Starfield Suwon, Shinsegae''s flagship ''second-generation'' Starfield mall opened January 26, 2024** as the fifth Starfield mall. ~334,000 m² gross floor area — Korea''s 2nd-largest indoor mall after Starfield Hanam. Designed in collaboration with **BCHO Partners (Cho Byoung-soo)** — the Korean firm responsible for the original COEX Starfield Library (2017). \n\nSuwon''s library represents the second-generation iteration with **bookshelves rising up to 22 meters tall** — among the tallest cylindrical bookshelf structures in any Korean public space; the library spans 4 floors (4F-7F atrium space) housing **a large on-site collection of books and magazines** including Korean and international publications, periodicals, art books, and a dedicated children''s section on 4F. \n\n**FREE and open to the public** during all mall hours (10:00-22:00 daily). No library card required, no admission fee. Books cannot be borrowed (read-on-site only). Distinctive features: **Vinyl Record Listening Lounge** with curated Korean indie + jazz/classic rock vinyl; **monthly rotating art exhibition** in the atrium; and **seasonal cherry blossom installation in the central atrium (March-April)** with thousands of pink LED petals — one of Suwon''s most photographed spring spots. \n\nAdjacent mall amenities: **Eatopia food hall (B1F)** with 30+ restaurants; **Aquafield Suwon water park + Korean spa (B1-2F)** separate paid admission; **Toy Kingdom (4F, Korea''s largest toy store)**; **CGV/MEGABOX dual cinema setup**. \n\n**Free Starfield shuttle bus** runs from Suwon Station Exit 4 every 10-15 min — the easiest access from public transit. **Reset stop** in the day — covered indoor environment that resets pace before Gwangmyeong Cave''s 30-min coach drive. \n\n**Café break + library photo + retail browse** — designed for a relaxed transition rather than another high-engagement attraction.", "highlights": ["**Shinsegae''s flagship 2nd-generation Starfield mall — opened January 26, 2024**", "BCHO Partners design (also designers of original COEX Starfield Library)", "**4-floor library with 22-meter bookshelves** — among Korea''s tallest", "Large open reading collection accessible FREE", "Vinyl Record Listening Lounge", "Cherry blossom LED-petal installation (March-April)", "Eatopia food hall, Aquafield water park, Toy Kingdom, CGV+MEGABOX cinema", "Free Starfield shuttle from Suwon Station Exit 4 (~10 min)", "**Rooftop installation ''The Planets'' by Canadian novelist-designer Douglas Coupland** — exclusive to the Suwon location (not at Seoul COEX); positions Starfield Suwon as a **''second-generation'' flagship** in Shinsegae''s library-mall format, designed by **BCHO Partners (Cho Byoung-soo)** rather than the often-misattributed Dutch firm MVRDV"], "timeUsed": ["15-min coach drive from Paldalmun Plaza to Starfield", "Mall + library walking tour (~45 min)", "Café break or shopping browse (~20 min)", "Reassembly at coach (~10 min)", "Optional Vinyl LP cafe lounge (5F, ~₩18,500 incl. drink + headphones + LP record-player access; ~30-45 min)"], "whyOnRoute": "The ''modern Korea'' counterweight after fortress + palace + market lunch. Shinsegae''s flagship 2nd-generation Starfield mall opened January 26, 2024; the four-floor library with 22 m bookshelves is the architectural highlight. **All-indoor reset stop** — buffers afternoon weather risk and provides genuine multi-generational appeal before Gwangmyeong Cave''s industrial-heritage finale. Starfield Library is the **single most Instagram-photographed indoor space in Greater Seoul outside central Seoul** (per Korean travel-media surveys 2024-25) — the 22m bookshelves (vs Seoul COEX''s 13m) span mall floors 4F-7F as a connected atrium void. **FREE admission, no membership, photos permitted, mall-wide free entry** — a no-friction photo stop with optional cafe/dining adjacency (Eatopia food hall on B1F with 30+ Korean and international restaurants). From Suwon Station: free Starfield shuttle bus (every 10-15 min from Suwon Station Exit 4) or Subway Line 1 → Hwaseo Station Exit 1/4 (8-min walk). Mall hours **10:00-22:00 daily**, library accessible during all mall hours.", "visitBasics": {"hours": "Mall 10:00-22:00; library accessible during all mall hours", "closed": "1-2 monthly closure days (typically Mondays — verify online)", "admission": "Library FREE; mall-wide free entry; Aquafield separate ~25,000-35,000 KRW", "walking": "Easy — escalators and elevators between all floors; wheelchair/stroller accessible"}, "convenience": {"restroom": "Multiple restrooms on every floor; family-friendly stations", "parking": "Underground ~5,000 spaces; first 3 hours FREE with mall purchase 30,000 KRW+; coach lot for groups"}, "smartNotes": {"photo": "**Library central atrium with 22-meter bookshelves** from 4F looking down. Vinyl Record Lounge for retro aesthetic. Cherry blossom installation in atrium (March-April). Christmas tree (December).", "facilities": "Eatopia food hall B1F, Toy Kingdom 4F, Aquafield water park B1-2F, T-Joy + CGV + MEGABOX cinemas, free WiFi, multilingual customer service, tax-refund counters.", "tip": "**Library is FREE** — exceptional value attraction. **22-meter bookshelves = Korea''s tallest** (mention to guests for impact). **Cherry blossom installation March-April** is the seasonal must-see. Avoid Saturday afternoons (peak crowds). Verify Starfield monthly closure dates online."}, "_poi_meta": {"poi_key": "starfield_library_suwon", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-05-21", "sources": ["Starfield official", "VisitKorea", "Shinsegae press", "BCHO Partners", "Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)", "Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)", "Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)", "ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review", "Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]}, "image": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "images": ["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"], "imageCredits": [{"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "source": "atoc-korea"}, {"url": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp", "location": "Starfield Library Suwon", "caption": "Starfield Library Suwon — photo 1", "alt": "Starfield Library Suwon — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp", "location": "Starfield Library Suwon", "caption": "Starfield Library Suwon — photo 2", "alt": "Starfield Library Suwon — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp", "location": "Starfield Library Suwon", "caption": "Starfield Library Suwon — photo 3", "alt": "Starfield Library Suwon — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp", "location": "Starfield Library Suwon", "caption": "Starfield Library Suwon — photo 4", "alt": "Starfield Library Suwon — gallery image 4"}]}, {"number": 5, "time": "≈ 15:30", "duration": "100 min", "name": "Gwangmyeong Cave", "category": "Industrial-Heritage Themed Cave", "description": "**Gwangmyeong Cave (광명동굴)** — originally a **gold, silver, copper, and zinc mine** developed in **1912 during the Japanese colonial period** and operated for 60 years until 1972. Across its active years, the mine produced 52 kg of gold, 6,070 kg of silver, 1,247 tons of copper, and 3,247 tons of zinc — significant Japanese-colonial-era mineral extraction from Korea. \n\nAfter mining ceased, the abandoned tunnels were used for ~40 years as a **shrimp-paste (saeujeot) fermentation storage** facility — the cave''s stable ~12°C temperature and high humidity made it ideal for jeotgal (Korean fermented seafood) aging. \n\n**Gwangmyeong City purchased the cave in 2011** for 4.3 billion KRW from a private owner and reopened it August 2011 as **Korea''s first government-owned cave-tourism attraction**. Won the **2014 Korea Tourism Star Award (Korea''s tourism Oscar)** — the first city-government-developed attraction to win. \n\n**Total tunnel length 7.8 km** across multiple levels; **~2 km accessible to public** in themed zones. **Constant ~12°C (54°F) year-round** — naturally cool in summer (popular escape from Korean heatwaves) and warmer than outside in winter. \n\n**Bring a light jacket.** **Themed zones**: **Cave Aquarium** (Korea''s deepest indoor freshwater aquarium); **Wine Cave** (Korea''s largest underground wine cellar storing 200+ Korean and imported wines — wine tasting available 5,000 KRW for 3 wines); **LED Art Tunnel** (200-m tunnel with seasonal lighting themes — cherry blossom in spring, autumn foliage, snow/ice winter); **Yongmaru Dragon** (41-meter-long fiberglass dragon — Korea''s tallest indoor sculpture in any cave, the most viral social-media spot); **Fluorescent Mural** (wall paintings in natural fluorescent pigments visible only under UV/black light); **Music Hall** (200-seat acoustically optimized performance venue); and **Korean Folk Tale Cave Theme Park** with character installations from Korean folk tales (dokkaebi, tiger, rabbit). \n\nFilmed: K-drama **''Memories of the Alhambra'' (2018)**, **''A Korean Odyssey''**, **''Doctors''**, several variety shows. **~1.5 million visitors annually** (2024 figure) — one of Gyeonggi Province''s top-5 paid tourist attractions. \n\n**Closed Mondays.** Tue-Sun 09:00-18:00 (last entry 17:00). Adults 10,000 / Teenagers 5,000 / Children 3,000 KRW. Most main routes wheelchair-accessible (level surfaces, ramped sections).", "highlights": ["**Originally a gold/silver/copper/zinc mine** — operated 1912-1972 by Japanese colonial administration", "Reopened August 2011 as Korea''s first government-owned cave attraction", "**Won Korea Tourism Star Award 2014** (Korea''s tourism Oscar)", "Total tunnel length 7.8 km; ~2 km accessible public route", "**Constant ~12°C year-round** — bring light jacket", "**41-meter fiberglass dragon (Yongmaru)** — Korea''s tallest indoor cave sculpture", "Wine Cave — Korea''s largest underground wine cellar (200+ wines; tasting 5,000 KRW)", "LED Art Tunnel + Fluorescent Mural + Music Hall + Cave Aquarium", "Filming: ''Memories of the Alhambra'' (2018), ''A Korean Odyssey''", "**Closed Mondays** — Tue-Sun 09:00-18:00", "Wheelchair-accessible primary route"], "timeUsed": ["30-min coach drive from Starfield Suwon to Gwangmyeong", "Cave entrance + ticketing (~10 min)", "Themed-zone walk: Aquarium → LED Tunnel → Dragon → Music Hall → Wine Cave → Folk Park (~70-80 min)", "Optional wine tasting (~15 min, extra)", "Reassembly at coach (~10 min)"], "whyOnRoute": "The day''s industrial-heritage anchor and **all-indoor finale** — buffers any late-afternoon weather risk while delivering Korea''s strongest cave-tourism experience. The 1912-1972 mining backstory + 2011 reopening + LED-art transformation is the most narratively compelling industrial-heritage story in the catalog. Wheelchair-accessible primary route makes it the most mobility-friendly heritage stop on the day. Gwangmyeong Cave''s **layered industrial-heritage narrative** is the unique selling point: a 1912 Japanese-colonial-era gold/silver/copper/zinc mine operated for 60 years (1912-1972), abandoned, repurposed as shrimp-paste fermentation storage for ~40 years (thanks to the constant **~12°C / 54°F year-round cave temperature** + high humidity), and finally **purchased by Gwangmyeong City in 2011** for 4.3 billion KRW from a private owner, becoming **Korea''s first government-owned cave-tourism attraction**. Won the Korea Tourism Star Award 2014. The **2 km accessible visitor route** (out of 7.8 km total tunnel length) packs Cave Aquarium + 200-m LED Art Tunnel + Wine Cave (Korea''s largest underground wine cellar with 200+ Korean and imported wines) + 200-seat Music Hall + 41-meter Yongmaru fiberglass dragon (tallest indoor cave sculpture in Korea) within ~1.5-2 hours.", "visitBasics": {"hours": "Tue-Sun 09:00-18:00 (last entry 17:00); summer Jul-Aug extended weekends to 19:00", "closed": "**Mondays** (open if Mon is public holiday, closed next day instead)", "admission": "Adults 10,000 / Teenagers 5,000 / Children 3,000 KRW; FREE for children ≤6 and seniors 65+", "walking": "Easy to moderate — main route ~2 km, mostly level paved cave floor; wheelchair-accessible primary route"}, "convenience": {"restroom": "At main entrance, mid-cave (Music Hall area), and exit", "parking": "Large dedicated lot (~1,000 spaces); 2,000 KRW for cars / 5,000 KRW for buses; coach lot for groups"}, "smartNotes": {"photo": "**LED Art Tunnel** seasonal-themed lighting (spring cherry blossom, autumn foliage, winter snow) — most photographed zone. **41-m Dragon (Yongmaru)** — viral social-media spot. **Fluorescent Mural** under UV light. **Wine Cave bottle walls** with Korean wine producer labels.", "facilities": "Cave restaurant (Korean-style buffet ~15,000 KRW), café with cave-aged wine list, gift shop, Wine Cave tasting room (5,000 KRW for 3 wines), Music Hall performance schedule.", "tip": "**12°C year-round — bring light jacket** even in summer. Perfect for **summer escape from Korean heatwaves**. **Skip Mondays** — closed. **Wine tasting** (5,000 KRW for 3 wines) is the most underrated experience — Korean wines from regional wineries you can''t find in Seoul. Plan 1.5-2 hours minimum; 2.5 hours with wine tasting and Music Hall concert."}, "_poi_meta": {"poi_key": "gwangmyeong_cave", "verified": true, "match": "single_poi", "kb_version": "1.28", "verified_date": "2026-05-21", "sources": ["VisitKorea", "Wikipedia", "Gwangmyeong City", "KoreaToDo", "Korea Tourism Organization (english.visitkorea.or.kr — Gwangmyeong Cave official listing)", "Gwangmyeong Cave official (gmcave.gm.go.kr — themed zones + operating hours + admission)", "Gwangmyeong City Tourism (gm.go.kr/tour — 2011 city purchase 4.3 billion KRW + Korea''s first govt-owned cave-tourism)", "Wikipedia (Gwangmyeong Cave — 1912 Japanese colonial mine + 1972 closure + 7.8 km tunnel total)", "Korea Tourism Star Award archive (Gwangmyeong Cave 2014 winner — Best New Tourist Attraction)"]}, "image": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp", "images": ["/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp", "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp", "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp", "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp"], "imageCredits": [{"url": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp", "source": "atoc-korea"}, {"url": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp", "source": "atoc-korea"}, {"url": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-15.webp", "location": "Gwangmyeong Cave", "caption": "Gwangmyeong Cave — photo 1", "alt": "Gwangmyeong Cave — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-22.webp", "location": "Gwangmyeong Cave", "caption": "Gwangmyeong Cave — photo 2", "alt": "Gwangmyeong Cave — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-10-12-03-28.webp", "location": "Gwangmyeong Cave", "caption": "Gwangmyeong Cave — photo 3", "alt": "Gwangmyeong Cave — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/gwangmyeong-cave/chatgpt-image-2026-5-9-11-48-09.webp", "location": "Gwangmyeong Cave", "caption": "Gwangmyeong Cave — photo 4", "alt": "Gwangmyeong Cave — gallery image 4"}]}, {"number": 6, "time": "≈ 17:30", "duration": "60 min", "name": "Return to Seoul", "category": "Return", "description": "Coach back to central Seoul via the **Seohaean Expressway** (different return route from the morning Gyeongbu Expressway approach — the geometric loop reflects Gwangmyeong''s western position vs. Suwon''s southern position). Drop-off at the same morning meeting points (Hongik University Station Exit 8 or Myeongdong Station Exit 2/4). Typical arrival **18:30-19:00** depending on Friday-evening / weekend traffic.", "highlights": ["Return via Seohaean Expressway from Gwangmyeong", "Drop-off at Hongik University or Myeongdong", "Typical arrival 18:30-19:00"], "timeUsed": ["Coach drive from Gwangmyeong to Seoul (~60 min)", "Drop-off at designated point"], "whyOnRoute": "Return logistics — Seohaean Expressway from Gwangmyeong is faster than backtracking via Gyeongbu Expressway from Suwon, exploiting the day''s geographic loop.", "visitBasics": {}, "convenience": {}, "smartNotes": {"tip": "Final arrival depends on Friday-evening / weekend traffic; on heavy days the drop-off may add 15-20 min."}, "_poi_meta": {"poi_key": "OPS_return", "verified": false, "match": "operational_implicit", "kb_version": "v1.14", "verified_date": "2026-04-29", "note": "Operational stop (return)"}, "_role": "dropoff"}], "routeFlowStops": [{"name": "Seoul", "type": "origin", "theme": "Departure"}, {"name": "Suwon Hwaseong Fortress", "type": "primary", "theme": "UNESCO Fortress"}, {"name": "Hwaseong Haenggung Palace", "type": "primary", "theme": "Heritage Palace"}, {"name": "Starfield Library Suwon", "type": "secondary", "theme": "Modern Korea"}, {"name": "Gwangmyeong Cave", "type": "primary", "theme": "Cave"}, {"name": "Seoul", "type": "return", "theme": "Return"}], "routePhases": [{"phase": "Outbound", "duration": "≈ 1 hour", "description": "Seoul → Suwon city via Gyeongbu Expressway."}, {"phase": "Heritage half", "duration": "≈ 3 hours", "description": "Suwon Hwaseong walls and Haenggung palace, all walking distance from each other."}, {"phase": "Modern hub", "duration": "≈ 1 hour", "description": "Drive 15 minutes to Starfield Suwon for the library and mall food hall."}, {"phase": "Underground finale", "duration": "≈ 1.5 hours", "description": "Drive 30 minutes northwest to Gwangmyeong Cave for the LED-lit themed park."}, {"phase": "Return", "duration": "≈ 1 hour", "description": "Gwangmyeong → Seoul via Seohaean Expressway."}], "routeShapeIntro": {"title": "How this day flows", "subtitle": "A triangular Gyeonggi loop south and southwest of Seoul: Suwon''s UNESCO fortress city for the morning, Suwon''s flagship modern mall for early afternoon, and Gwangmyeong''s transformed gold mine for the late-afternoon finale. Three different kinds of public space — military, commercial, industrial — across 250 years, in a single coach loop."}, "whyTourWorks": {"bestFor": ["First-time visitors to the area", "Couples", "Adult families", "Active travelers comfortable with full days", "Travelers who want UNESCO World Heritage stops"], "lessIdealFor": ["Travelers with claustrophobia or fear of confined spaces (Gwangmyeong Cave''s lower levels are narrow with low ceilings)", "Anyone unable to handle ≈180 stairs down/up at Gwangmyeong''s lower-level highlights (no elevator)", "Travelers with limited mobility on the fortress wall — steep sections and stairs at gates", "Visitors who want to see Seoul''s central palaces — this trip stays entirely in Gyeonggi", "Travelers who must visit on a Monday — Gwangmyeong Cave is closed for maintenance"], "routeLogicSections": [{"title": "Why this route is built this way", "icon": "route", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600", "items": [{"label": "More variety than the standard Suwon tour", "detail": "Most Suwon day tours combine the fortress, palace, and Starfield Library — three stops within ten minutes of each other. This version adds Gwangmyeong Cave, a completely different landscape (underground, art-themed, year-round 12°C) that you can''t easily reach from Suwon by public transit."}, {"label": "Indoor-friendly fallback for any weather", "detail": "Two of the four major stops — Starfield Library and Gwangmyeong Cave — are fully indoors and climate-controlled. The fortress walks are short enough to handle rain or summer heat. A reliable choice when the weather is dramatic."}, {"label": "Free admission, paid context", "detail": "Starfield Library is free to enter on your own — but it''s much more rewarding with a guide who can explain why a mall built it (Shinsegae''s MZ-generation strategy), how it differs from the COEX original, and where the best photo angles are without disturbing readers."}, {"label": "Cooler than a single-format day", "detail": "Heritage tours can feel relentless. Library-and-mall tours can feel light. This itinerary deliberately shifts gears — UNESCO walls, market food, modern library, then an LED-lit underground theme park — so the day doesn''t fall into a single rhythm."}]}, {"title": "How the walking load actually feels", "icon": "footprints", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600", "items": [{"label": "Fortress wall: hardest section", "detail": "≈1 km walked with steep gradients and stairs at gates. Comfortable shoes essential. Sweeping views reward the climb but it isn''t wheelchair-friendly."}, {"label": "Gwangmyeong Cave: ≈180 stairs each way", "detail": "Stairs to the lower-level highlights (Wine Cave, Golden Waterfall, Aqua World) and the same back. No elevator. Visitors with mobility limits stay on the upper level — still ≈40 min of content there."}, {"label": "Haenggung and Starfield: easy", "detail": "Palace and Starfield are flat and accessible, giving the route an easy stretch between the fortress walls and the cave stairs."}]}, {"title": "When weather and seasons shift", "icon": "cloud-sun", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600", "items": [{"label": "Summer heat: Gwangmyeong is the relief", "detail": "12°C constant inside the cave makes it the refuge stop on hot days. The wall walk lengthens shade breaks; market lunch shifts indoors at Starfield."}, {"label": "Winter cold: layer for the cave", "detail": "12°C is cool when outside is colder. Bring a light jacket inside Gwangmyeong even in summer; in winter, expect to keep your outdoor layer on."}, {"label": "Mondays are not available", "detail": "Gwangmyeong Cave closes Mondays for maintenance. Tour doesn''t operate. Pick the Folk Village or Waujeongsa version for Monday travel."}]}]}, "practicalAccordionItems": [{"id": "inclusions", "title": "What''s included", "preview": "Round-trip coach transport from Seoul, English-speaking tour guide, Suwon Hwaseong…", "content": ["Round-trip coach transport from Seoul, English-speaking tour guide, Suwon Hwaseong Fortress admission, Hwaseong Haenggung Palace admission, Gwangmyeong Cave admission.", "Not included: meals, drinks, optional cave-winery tasting, tips.", "Starfield Library entry is free."]}, {"id": "pickup", "title": "Pickup & drop-off", "preview": "Hongik University Station (Exit 8) at ≈08:00 or Myeongdong Station (Exit 2 or 4) at ≈08:30.", "content": ["Hongik University Station (Exit 8) at ≈08:00 or Myeongdong Station (Exit 2 or 4) at ≈08:30.", "Arrive 10 minutes early.", "There is no hotel pickup; meeting points only.", "Latecomers cannot be accommodated and are non-refundable."]}, {"id": "walking", "title": "Walking & terrain", "preview": "Moderate.", "content": ["Moderate.", "The fortress wall walk involves uphill stone steps.", "Gwangmyeong Cave has approximately 180 steps down to the lower levels and back up — there is no elevator.", "Comfortable closed-toe walking shoes are essential.", "Not recommended if you have significant mobility limitations."]}, {"id": "what", "title": "What to wear & bring", "preview": "Comfortable walking shoes (sneakers or hiking shoes), a light jacket — Gwangmyeong Cave…", "content": ["Comfortable walking shoes (sneakers or hiking shoes), a light jacket — Gwangmyeong Cave is 12°C year-round, so even in summer it''s chilly.", "In winter, bring a warm coat for the fortress wall and a lighter layer for the cave.", "Camera, water, cash for lunch and street food (₩10,000–₩20,000 budget)."]}, {"id": "cancellation", "title": "Cancellation", "preview": "Free cancellation up to 24 hours before the tour starts.", "content": ["Free cancellation up to 24 hours before the tour starts.", "Same-day cancellations and no-shows are non-refundable.", "Tour does not operate on Mondays (Gwangmyeong Cave closed)."]}, {"id": "children", "title": "Children & accessibility", "preview": "Children typically enjoy this tour — the cave''s lights, dragon sculpture, and Aqua World…", "content": ["Children typically enjoy this tour — the cave''s lights, dragon sculpture, and Aqua World are popular with families.", "The fortress walk has stairs and uneven surfaces.", "The cave''s 180+ stairs make it unsuitable for guests with mobility issues, strollers, or fear of confined spaces."]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "See seasonal notes"}, "tomorrow": {"temp": "—", "label": "See seasonal notes"}, "_seasonalSummary": "Suwon and Gwangmyeong track Seoul''s weather closely (about 30 km south/southwest). Plan for hot, humid summers and cold, dry winters; the cave is a constant 12°C year-round, providing relief in summer and shelter in winter.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "5–22°C", "notes": "Cherry blossoms along the fortress wall in early–mid April."}, {"season": "Summer (Jun–Aug)", "range": "22–32°C", "notes": "Hot and humid; cave is a cool refuge."}, {"season": "Autumn (Sep–Nov)", "range": "8–22°C", "notes": "Best season — clear skies, mild temperatures."}, {"season": "Winter (Dec–Feb)", "range": "-5 to 6°C", "notes": "Cold winds on the fortress wall; library and cave are climate-controlled."}]}, "seasonalVariations": [{"season": "Spring", "description": "Cherry blossoms along the Hwaseong wall; cave opens spring-themed light installations."}, {"season": "Summer", "description": "Cave''s 12°C interior is a popular escape from Seoul''s humidity; Suwon Hwaseong Cultural Festival in summer."}, {"season": "Autumn", "description": "Maple foliage along the fortress wall; major Suwon Hwaseong Cultural Festival in October."}, {"season": "Winter", "description": "Snow on the fortress wall is a classic photo; cave hosts year-round LED tableaux undisturbed by weather."}], "bookingTrustItems": [{"icon": "check-circle", "title": "Licensed local operator", "description": "Authorized Korean tour operator with full insurance", "iconBg": "bg-emerald-50/80", "iconColor": "text-emerald-600"}, {"icon": "route", "title": "Route specialists", "description": "Hand-tuned itinerary, not a generic loop", "iconBg": "bg-sky-50/80", "iconColor": "text-sky-600"}, {"icon": "users", "title": "Curated group size", "description": "Right-sized for the route", "iconBg": "bg-amber-50/80", "iconColor": "text-amber-600"}], "bookingSupportSteps": [{"timing": "Immediately", "title": "Instant Confirmation", "detail": "Booking confirmation with itinerary summary"}, {"timing": "12 hours before", "title": "12-Hour Reminder", "detail": "Weather update and any route adjustments"}, {"timing": "Evening before", "title": "Final Pickup Info", "detail": "Exact pickup time and driver contact"}, {"timing": "Morning of tour", "title": "Day-of Route Notes", "detail": "Morning briefing based on live conditions"}, {"timing": "During tour", "title": "Stop-by-Stop Tips", "detail": "Real-time guidance at each location"}, {"timing": "After tour", "title": "Post-tour Support", "detail": "Follow-up and recommendations"}], "staticQuestions": [{"id": "q1", "question": "Why isn''t the tour available on Mondays?", "answer": "Gwangmyeong Cave is closed on Mondays for maintenance. Since the cave is one of the four core stops, the tour doesn''t operate on Mondays. If you want to visit on a Monday, consider the Suwon-only itineraries (Hwaseong + Folk Village or Hwaseong + Waujeongsa)."}, {"id": "q2", "question": "Are admissions included?", "answer": "Yes — Suwon Hwaseong Fortress, Hwaseong Haenggung Palace, and Gwangmyeong Cave admissions are all included. Starfield Library is free for everyone. Optional cave-winery tasting and any folk-village extras are at your own cost."}, {"id": "q3", "question": "Is lunch included?", "answer": "No. Lunch is typically eaten during free time at Starfield Suwon''s food hall (large variety, ₩10,000–₩20,000) or at a small Suwon eatery near the fortress (Suwon-style galbi or chicken)."}, {"id": "q4", "question": "How many stairs are in Gwangmyeong Cave?", "answer": "Approximately 180 steps down to the lower-level highlights (Wine Cave, Golden Waterfall, Aqua World) and the same back up. There is no elevator. Visitors with mobility issues or fear of confined spaces typically stay on the upper level."}, {"id": "q5", "question": "Is the cave warm or cold?", "answer": "Cool. The cave is a constant 12°C (54°F) year-round. In summer that''s a relief; in winter, you''ll want to keep a layer on. Summer visitors often bring a light jacket just for this stop."}, {"id": "q6", "question": "How is this different from the Suwon + Folk Village tour?", "answer": "Both visit the fortress, palace, and Starfield Library. This version pairs them with Gwangmyeong Cave (an underground LED-lit theme park). The Folk Village version drops the cave and adds the Korean Folk Village in Yongin (a 270-house open-air heritage park). Choose this one for variety and indoor weather; the Folk Village version for deeper Joseon-era heritage."}, {"id": "first-time", "question": "Is this a good choice for first-time visitors to Suwon & Gwangmyeong?", "answer": "Yes — strong first-time pick for travelers who want one UNESCO site (Hwaseong Fortress), one Joseon palace (Haenggung), one underground themed attraction (Gwangmyeong Cave), and one contemporary photo space (Starfield Library) in a single day. The format gives four very different cultural angles. Note: the tour doesn''t operate on Mondays (Gwangmyeong Cave maintenance day)."}, {"id": "walking", "question": "Is the walking difficult?", "answer": "Active walking day with one heavy stair section. Hwaseong wall has steep sections and stairs (≈1 km walked). Gwangmyeong Cave''s lower-level highlights require ≈180 stairs down and the same back up — no elevator. Haenggung Palace is mostly flat with some courtyard steps. Starfield Library is fully escalator/elevator-accessible. Total walking ≈4 km. Comfortable shoes essential, especially for the cave stairs."}, {"id": "family", "question": "Is this tour suitable for families?", "answer": "Yes for families whose kids can handle the wall walk and Gwangmyeong''s stairs. The cave is a kid favorite — LED-lit tableaux, Aqua World aquarium, the 41 m dragon sculpture, the underground winery (parents only) and Golden Waterfall. Strollers don''t work on the wall or in the cave''s stair sections. Year-round 12°C inside the cave makes it a relief stop."}, {"id": "seniors", "question": "Can older adults join comfortably?", "answer": "Recommended only for active seniors comfortable with stairs and confined spaces. The 180 stairs at Gwangmyeong''s lower levels have no elevator alternative — the upper level (≈40 min of content) is accessible if stairs aren''t possible. The fortress wall has steep sections; easier flat segments are walkable. Haenggung and Starfield are fully accessible. Bring a light layer for the cave even in summer."}, {"id": "children", "question": "What''s the recommended minimum age?", "answer": "Best fit is around age 10 and up. The fortress wall has uneven surfaces, the cave has 180 stairs each way, and the day is long (9 hours). Younger kids can manage if comfortable on stairs and with confined spaces (the cave''s lower tunnels are narrow). Kids often love the cave''s underground attractions — dragon sculpture, Aqua World, Wine Cave (visual only). The Suwon street-food market works for all ages."}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.", "price": {"amountLabel": "52", "currency": "USD", "per": "person", "salePriceUsd": 52, "originalPriceUsd": 59, "discountPercent": 12}}, "pickup_dropoff": {"departure": [{"order": 1, "time": "08:00", "name": "Hongik Univ. Station (Exit 8)", "type": "station", "lat": 37.55753, "lng": 126.92447}, {"order": 2, "time": "08:30", "name": "Myeongdong Station (Exit 2 or 4)", "type": "station", "lat": 37.56099, "lng": 126.98619}], "return": [{"order": 1, "name": "Hongik Univ. Station (Exit 8)", "ty