  full_document = '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "seoul-suwon-hwaseong-folk-village-starfield-library", "locale": "en", "product_id": "seoul-suwon-hwaseong-folk-village-starfield-library", "seo": {"pageTitle": "Suwon Hwaseong, Folk Village & Starfield Library | AtoC Korea", "metaDescription": "10-hour small-group day tour from Seoul: UNESCO Suwon Hwaseong Fortress, Hwaseong Haenggung Palace, Korean Folk Village (Yongin), and Starfield Suwon Library.", "primaryKeywords": ["Suwon Hwaseong tour from Seoul", "Korean Folk Village day trip", "Starfield Library Suwon tour", "UNESCO Korea day tour"], "ogImage": "https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "title": "Suwon Hwaseong, Korean Folk Village & Starfield Library Day Tour from Seoul | AtoC Korea"}, "catalog_card": {"thumbnail": "/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp", "title": "Suwon: Hwaseong, Folk Village & Starfield", "priceLabel": "From US$60 per person (was $66, 9% off)", "shortCardDescription": "A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed Suwon Hwaseong Fortress (18th-century walls and gates), the restored Hwaseong Haenggung Palace with its Joseon-era reenactments, the immersive open-air Korean Folk Village in Yongin, and the dramatic four-floor Starfield Library Suwon. 10 hours with included transport and admissions.", "tags": ["small_group", "culture", "unesco", "heritage", "library", "folk_village", "day_trip"], "rating": 0, "reviewCount": 0, "slug": "seoul-suwon-hwaseong-folk-village-starfield-library", "subtitle": "A small-group cultural day-trip from Seoul to Gyeonggi Province covering four contrasting sides of Korean heritage and modern life: the UNESCO-listed…", "region": "Gyeonggi-do (south of Seoul)", "duration": "10 hours", "stopsCount": 6, "badges": ["Small Group", "Culture", "UNE