  full_document = '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "seoul-seoraksan-naksansa-temple-naksan-beach-day-trip", "locale": "en", "product_id": "seoul-seoraksan-naksansa-temple-naksan-beach-day-trip", "seo": {"pageTitle": "Gangwon-do Day Tour from Seoul: Seoraksan & Naksansa Temple | AtoC Korea", "metaDescription": "12-hour coach day trip from Seoul to the East Sea coast: Seoraksan National Park, cliffside Naksansa Temple, and Naksan Beach. Guided, transfers included.", "primaryKeywords": ["Seoul Seoraksan day tour", "Naksansa Temple tour", "Seoraksan day trip from Seoul", "Naksan Beach tour", "Seoraksan Naksansa one-day tour"], "ogImage": "https://www.atockorea.com/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp", "title": "Gangwon-do Day Tour from Seoul · Seoraksan + Naksansa Temple + Naksan Beach | AtoC Korea", "description": "Coach day tour from Seoul to Korea''s most iconic national park (Seoraksan), a thousand-year cliffside temple above the sea (Naksansa), and the pine-backed sands of Naksan Beach — a mountain-to-ocean day on the East Sea coast."}, "catalog_card": {"thumbnail": "/images/tours/seoraksan-national-park/seoraksan-ridge-view.webp", "title": "Gangwon-do Day Tour from Seoul: Seoraksan + Naksansa Temple + Naksan Beach", "priceLabel": "From US$53 per person (was $58, 9% off)", "shortCardDescription": "A 12-hour coach day trip from Seoul to the East Sea coast: hike Seoraksan National Park, visit the cliffside Naksansa Temple, and walk pine-backed Naksan Beach. Departs Mondays and Thursdays with an English-speaking guide and round-trip transfers from Hongik or Myeongdong.", "tags": ["Day trip from Seoul", "Coach tour", "Nature & temples", "East Sea coast", "Autumn foliage"], "rating": 0, "reviewCount": 0, "slug": "seoul-seoraksan-naksansa-temple-naksan-beach-day-trip", "subtitle": "Seoraksan''s granite peaks, a thousand-year seaside temple, and a pine-backed East Sea beach in a single 12-hour Seoul da